:root {
  --card-bg: #ffffff;
  --header-bg: #1a2e4a;
  --bank-label-color: #ffffff;
  --account-type-color: #90aac8;
  --balance-label-color: #90aac8;
  --balance-amount-color: #ffffff;
  --stat-income-bg: #e8f7ef;
  --stat-expense-bg: #fdecea;
  --stat-savings-bg: #eef2ff;
  --income-icon-color: #22a05a;
  --expense-icon-color: #e03e30;
  --savings-icon-color: #4f62d6;
  --stat-label-color: #6b7280;
  --income-value-color: #22a05a;
  --expense-value-color: #e03e30;
  --savings-value-color: #4f62d6;
  --section-title-color: #374151;
  --tx-name-color: #1f2937;
  --tx-date-color: #9ca3af;
  --credit-color: #22a05a;
  --debit-color: #e03e30;
  --dot-green: #22a05a;
  --dot-red: #e03e30;
  --divider-color: #f0f0f0;
  --border-radius-card: 14px;
  --border-radius-stat: 10px;
}

.card {
  background: var(--card-bg);
  border-radius: var(--border-radius-card);
  width: 500px;
  overflow: hidden;
}

.card-header {
  background: var(--header-bg);
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 20px;
}

.header-left {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.bank-label {
  color: var(--bank-label-color);
  font-size: 18px;
  font-weight: 700;
  line-height: 1;
}

.account-type {
  color: var(--account-type-color);
  font-size: 12px;
  font-weight: 400;
}

.balance-block {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 4px;
}

.balance-label {
  color: var(--balance-label-color);
  font-size: 11px;
  font-weight: 400;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.balance-amount {
  color: var(--balance-amount-color);
  font-size: 22px;
  font-weight: 700;
  line-height: 1;
}

.stats-row {
  display: flex;
  gap: 10px;
  padding: 14px 20px;
  border-bottom: 1px solid var(--divider-color);
}

.stat-box {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  border-radius: var(--border-radius-stat);
}

.stat-box.income {
  background: var(--stat-income-bg);
}

.stat-box.expense {
  background: var(--stat-expense-bg);
}

.stat-box.savings {
  background: var(--stat-savings-bg);
}

.stat-icon {
  font-size: 18px;
  line-height: 1;
}

.stat-box.income .stat-icon {
  color: var(--income-icon-color);
}

.stat-box.expense .stat-icon {
  color: var(--expense-icon-color);
}

.stat-box.savings .stat-icon {
  color: var(--savings-icon-color);
}

.stat-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.stat-label {
  color: var(--stat-label-color);
  font-size: 11px;
  font-weight: 500;
}

.stat-value {
  font-size: 13px;
  font-weight: 700;
  line-height: 1;
}

.stat-box.income .stat-value {
  color: var(--income-value-color);
}

.stat-box.expense .stat-value {
  color: var(--expense-value-color);
}

.stat-box.savings .stat-value {
  color: var(--savings-value-color);
}

.transactions {
  padding: 12px 20px 16px;
}

.section-title {
  color: var(--section-title-color);
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 10px;
}

.tx-list {
  display: flex;
  flex-direction: column;
  gap: 0px;
}

.tx-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 9px 0;
  border-bottom: 1px solid var(--divider-color);
}

.tx-row:last-child {
  border-bottom: none;
}

.tx-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}

.tx-dot.dot-green {
  background: var(--dot-green);
}

.tx-dot.dot-red {
  background: var(--dot-red);
}

.tx-name {
  flex: 1;
  color: var(--tx-name-color);
  font-size: 13px;
  font-weight: 500;
}

.tx-date {
  color: var(--tx-date-color);
  font-size: 12px;
  font-weight: 400;
  min-width: 40px;
  text-align: right;
}

.tx-amount {
  font-size: 13px;
  font-weight: 700;
  min-width: 80px;
  text-align: right;
}

.tx-amount.credit {
  color: var(--credit-color);
}

.tx-amount.debit {
  color: var(--debit-color);
}
